        'terms_content' => '<div class="col-12">
        <h1 class="wp-block-heading">Términos y Condiciones</h1>
        <h2 class="wp-block-heading">1. General</h2>
        <p>1.1. Bienvenido a myalphaguide.com (el “Sitio Web”).</p>
